                    <td class="text-right">{{ row.qty }} {{ row.uom }}</td>
                    <td class="text-right">{{ row.qty }} {{ row.uom }}</td>
                    <td class="text-right">{{ row.get_formatted("rate") }}</td>
                    <td>{{ row.uom }}</td>
                    <td class="text-right bold">{{ row.get_formatted("amount") }}</td>
                </tr>
                {% endfor %}

                {% for tax in doc.taxes %}
                <tr>
                    <td></td><td></td>
                    <td class="text-right">
                        {% if 'Round' in tax.account_head %}
                            <i>Less : &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span class="bold">{{ tax.description }}</span></i>
                        {% else %}
                            <i class="bold">{{ tax.description }}</i>
                        {% endif %}
                    </td>
                    <td></td><td></td><td></td><td></td><td></td><td></td>
                    <td class="text-right bold">{{ tax.get_formatted("tax_amount") }}</td>
                </tr>
                {% endfor %}


                {% if doc.rounding_adjustment %}
                <tr>
                    <td></td><td></td>
                    <td class="text-right">
                        <i>{% if doc.rounding_adjustment < 0 %}Less : &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {% endif %}<span class="bold">Round Off</span></i>
                    </td>
                    <td></td><td></td><td></td><td></td><td></td><td></td>
                    <td class="text-right bold">{% if doc.rounding_adjustment < 0 %}(-){{ frappe.utils.fmt_money(doc.rounding_adjustment | abs, currency=doc.currency) }}{% else %}{{ frappe.utils.fmt_money(doc.rounding_adjustment, currency=doc.currency) }}{% endif %}</td>
                </tr>
                {% endif %}

                <tr style="height: 120px;">
                    <td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td>
                </tr>

                <tr class="items-total-row">
                    <td></td><td></td>
                    <td class="text-right bold">Total</td>
                    <td></td><td></td>
                    <td class="text-right bold">{{ doc.total_qty }}</td>
                    <td class="text-right bold">{{ doc.total_qty }}</td>
                    <td></td><td></td>
                    <td class="text-right bold">{{ doc.get_formatted("rounded_total") if doc.rounded_total else doc.get_formatted("grand_total") }}</td>
                </tr>
            </tbody>
        </table>

        <div style="padding: 4px; border-bottom: 1px solid #000;">
            <div style="float: right; font-style: italic;">E. & O.E</div>
            <span style="font-size: 9px;">Amount Chargeable (in words)</span><br>
            <span class="bold">{{ frappe.utils.money_in_words(doc.rounded_total or doc.grand_total, doc.currency) }}</span>
        </div>

        <table class="hsn-table">
            <thead>
                <tr>
                    <th rowspan="2" width="25%">HSN/SAC</th>
                    <th rowspan="2" width="15%">Taxable<br>Value</th>
                    {% if ns.igst_rate > 0 %}
                    <th colspan="2">IGST</th>
                    {% else %}
                    <th colspan="2">CGST</th>
                    <th colspan="2">SGST/UTGST</th>
                    {% endif %}
                    <th rowspan="2" width="15%">Total<br>Tax Amount</th>
                </tr>
                <tr>
                    {% if ns.igst_rate > 0 %}
                    <th width="10%" style="border-top: 1px solid #000;">Rate</th>
                    <th width="12%" style="border-top: 1px solid #000; border-right: 1px solid #000;">Amount</th>
                    {% else %}
                    <th width="10%" style="border-top: 1px solid #000;">Rate</th>
                    <th width="12%" style="border-top: 1px solid #000;">Amount</th>
                    <th width="10%" style="border-top: 1px solid #000;">Rate</th>
                    <th width="12%" style="border-top: 1px solid #000; border-right: 1px solid #000;">Amount</th>
                    {% endif %}
                </tr>
            </thead>
            <tbody>
                {%- set t_taxable = namespace(v=0) -%}
                {%- set t_cgst = namespace(v=0) -%}
                {%- set t_sgst = namespace(v=0) -%}
                {%- set t_igst = namespace(v=0) -%}
                {%- for hsn_code, hsn_items in doc.items | groupby('gst_hsn_code') -%}
                {%- set r = namespace(taxable=0) -%}
                {%- for item in hsn_items -%}
                    {%- set r.taxable = r.taxable + (item.net_amount if item.net_amount else item.amount) -%}
                {%- endfor -%}
                {%- if ns.igst_rate > 0 -%}
                    {%- set r_igst = r.taxable * ns.igst_rate / 100 -%}
                    {%- set r_total_tax = r_igst -%}
                    {%- set t_igst.v = t_igst.v + r_igst -%}
                {%- else -%}
                    {%- set r_cgst = r.taxable * ns.cgst_rate / 100 -%}
                    {%- set r_sgst = r.taxable * ns.sgst_rate / 100 -%}
                    {%- set r_total_tax = r_cgst + r_sgst -%}
                    {%- set t_cgst.v = t_cgst.v + r_cgst -%}
                    {%- set t_sgst.v = t_sgst.v + r_sgst -%}
                {%- endif -%}
                {%- set t_taxable.v = t_taxable.v + r.taxable -%}
                <tr>
                    <td>{{ hsn_code or "-" }}</td>
                    <td>{{ frappe.utils.fmt_money(r.taxable, currency=doc.currency) }}</td>
                    {% if ns.igst_rate > 0 %}
                    <td>{{ ns.igst_rate }}%</td>
                    <td>{{ frappe.utils.fmt_money(r_igst, currency=doc.currency) }}</td>
                    {% else %}
                    <td>{{ ns.cgst_rate }}%</td>
                    <td>{{ frappe.utils.fmt_money(r_cgst, currency=doc.currency) }}</td>
                    <td>{{ ns.sgst_rate }}%</td>
                    <td>{{ frappe.utils.fmt_money(r_sgst, currency=doc.currency) }}</td>
                    {% endif %}
                    <td>{{ frappe.utils.fmt_money(r_total_tax, currency=doc.currency) }}</td>
                </tr>
                {%- endfor -%}

                <tr class="bold">
                    <td class="text-right">Total</td>
                    <td>{{ frappe.utils.fmt_money(t_taxable.v, currency=doc.currency) }}</td>
                    {% if ns.igst_rate > 0 %}
                    <td></td>
                    <td>{{ frappe.utils.fmt_money(t_igst.v, currency=doc.currency) }}</td>
                    {% else %}
                    <td></td>
                    <td>{{ frappe.utils.fmt_money(t_cgst.v, currency=doc.currency) }}</td>
                    <td></td>
                    <td>{{ frappe.utils.fmt_money(t_sgst.v, currency=doc.currency) }}</td>
                    {% endif %}
                    <td>{{ frappe.utils.fmt_money(t_cgst.v + t_sgst.v + t_igst.v, currency=doc.currency) }}</td>
                </tr>
            </tbody>
        </table>

        <div style="padding: 4px; border-bottom: 1px solid #000;">
            <span style="font-size: 9px;">Tax Amount (in words) :</span>
            <span class="bold" style="margin-left: 10px;">{{ frappe.utils.money_in_words(doc.total_taxes_and_charges, doc.currency) }}</span>
        </div>

        <div class="footer-section">
            <span style="font-size: 9px; text-decoration: underline;">Declaration</span><br>
            <span style="font-size: 9px;">We declare that this invoice shows the actual price of the goods described and that all particulars are true and correct.</span>

            <div class="sign-table">
                <div class="sign-cell sign-left">
                    Customer's Seal and Signature
                </div>
                <div class="sign-cell sign-right">
                    for <span class="bold">{{ doc.company }}</span><br><br><br><br>
                    Authorised Signatory
                </div>
            </div>
        </div>
    </div>

    <div style="text-align: center; font-size: 9px; margin-top: 5px;">This is a Computer Generated Invoice</div>
</div>

{%- macro compact_address(address) -%}
    {%- if address -%}
        {%- set cleaned_address = address | replace('<br />', '\n') | replace('<br/>', '\n') | replace('<br>', '\n') -%}
        {%- for line in cleaned_address.split('\n') -%}
            {%- set clean_line = line | trim -%}
            {%- set lower_line = clean_line | lower -%}
            {%- if clean_line and lower_line != 'india' and lower_line[:8] != 'pin code' and lower_line[:5] != 'gstin' and lower_line[:10] != 'state name' and lower_line[:15] != 'place of supply' and 'state code' not in lower_line -%}
                <p>{{ clean_line }}</p>
            {%- endif -%}
        {%- endfor -%}
    {%- endif -%}
{%- endmacro -%}

{%- macro tally_state_line(address_name=None, gstin=None, place_of_supply=None) -%}
    {%- set ns = namespace(state_name='', state_code='') -%}
    {%- if address_name -%}
        {%- set address_doc = frappe.get_cached_doc('Address', address_name) -%}
        {%- set ns.state_name = address_doc.get('gst_state') or address_doc.get('state') or '' -%}
        {%- set ns.state_code = address_doc.get('gst_state_number') or '' -%}
    {%- endif -%}
    {%- if not ns.state_code and gstin -%}
        {%- set ns.state_code = gstin[:2] -%}
    {%- endif -%}
    {%- if not ns.state_name and place_of_supply and '-' in place_of_supply -%}
        {%- set ns.state_name = place_of_supply.split('-', 1)[1] | trim -%}
    {%- endif -%}
    {%- if not ns.state_code and place_of_supply and '-' in place_of_supply -%}
        {%- set ns.state_code = place_of_supply.split('-', 1)[0] | trim -%}
    {%- endif -%}
    {%- if ns.state_name or ns.state_code -%}
        <p>State Name : {{ ns.state_name }}{% if ns.state_code %}, Code : {{ ns.state_code }}{% endif %}</p>
    {%- endif -%}
{%- endmacro -%}

{%- macro tally_gstin_line(address_name=None, gstin=None) -%}
    {%- set ns = namespace(gstin=gstin or '') -%}
    {%- if address_name and not ns.gstin -%}
        {%- set address_doc = frappe.get_cached_doc('Address', address_name) -%}
        {%- set ns.gstin = address_doc.get('gstin') or '' -%}
    {%- endif -%}
    {%- if ns.gstin -%}
        <p>GSTIN/UIN: <span class="bold">{{ ns.gstin }}</span></p>
    {%- endif -%}
{%- endmacro -%}

{%- macro tally_place_of_supply(place_of_supply=None) -%}
    {%- if place_of_supply -%}
        {%- set pos_name = place_of_supply.split('-', 1)[1] | trim if '-' in place_of_supply else place_of_supply -%}
        <p>Place of Supply : {{ pos_name }}</p>
    {%- endif -%}
{%- endmacro -%}

<style>
