    /* HSN Table */
    .hsn-table {
        width: 100%;
        border-collapse: collapse;
        border-bottom: 1px solid #000;
        table-layout: fixed;
        empty-cells: show;
    }
    .hsn-table th, .hsn-table td {
        border-right: 1px solid #000;
        border-bottom: 1px solid #000;
        padding: 2px 4px;
        text-align: right;
        box-sizing: border-box;
    }
    .hsn-table th {
        text-align: center;
        font-weight: normal;
    }
    .hsn-table th:first-child, .hsn-table td:first-child {
        text-align: left;
    }
    .hsn-table th:last-child, .hsn-table td:last-child {
        border-right: none;
    }

    .footer-section {
        padding: 4px;
    }
    .sign-table {
        width: 100%;
        border-top: 1px solid #000;
        display: table;
