        {%- set ns.cgst_amt = ns.cgst_amt + tax.tax_amount -%}
    {%- elif 'sgst' in tax.description.lower() or 'utgst' in tax.description.lower() -%}
        {%- set ns.sgst_rate = tax.rate -%}
        {%- set ns.sgst_amt = ns.sgst_amt + tax.tax_amount -%}
    {%- elif 'igst' in tax.description.lower() -%}
        {%- set ns.igst_rate = tax.rate -%}
        {%- set ns.igst_amt = ns.igst_amt + tax.tax_amount -%}
    {%- endif -%}
{%- endfor -%}

