                    {%- set r_sgst = r.taxable * ns.sgst_rate / 100 -%}
                    {%- set r_total_tax = r_cgst + r_sgst -%}
                    {%- set t_cgst.v = t_cgst.v + r_cgst -%}
                    {%- set t_sgst.v = t_sgst.v + r_sgst -%}
                {%- endif -%}
                {%- set t_taxable.v = t_taxable.v + r.taxable -%}
                <tr>
                    <td>{{ hsn_code or "-" }}</td>
                    <td>{{ frappe.utils.fmt_money(r.taxable, currency=doc.currency) }}</td>
                    {% if ns.igst_rate > 0 %}
                    <td>{{ ns.igst_rate }}%</td>
                    <td>{{ frappe.utils.fmt_money(r_igst, currency=doc.currency) }}</td>
                    {% else %}
                    <td>{{ ns.cgst_rate }}%</td>
                    <td>{{ frappe.utils.fmt_money(r_cgst, currency=doc.currency) }}</td>
                    <td>{{ ns.sgst_rate }}%</td>
                    <td>{{ frappe.utils.fmt_money(r_sgst, currency=doc.currency) }}</td>
                    {% endif %}
                    <td>{{ frappe.utils.fmt_money(r_total_tax, currency=doc.currency) }}</td>
                </tr>
                {%- endfor -%}

                <tr class="bold">
                    <td class="text-right">Total</td>
                    <td>{{ frappe.utils.fmt_money(t_taxable.v, currency=doc.currency) }}</td>
                    {% if ns.igst_rate > 0 %}
                    <td></td>
                    <td>{{ frappe.utils.fmt_money(t_igst.v, currency=doc.currency) }}</td>
                    {% else %}
                    <td></td>
                    <td>{{ frappe.utils.fmt_money(t_cgst.v, currency=doc.currency) }}</td>
                    <td></td>
                    <td>{{ frappe.utils.fmt_money(t_sgst.v, currency=doc.currency) }}</td>
                    {% endif %}
                    <td>{{ frappe.utils.fmt_money(t_cgst.v + t_sgst.v + t_igst.v, currency=doc.currency) }}</td>
                </tr>
            </tbody>
        </table>

        <div style="padding: 4px; border-bottom: 1px solid #000;">
            <span style="font-size: 9px;">Tax Amount (in words) :</span>
            <span class="bold" style="margin-left: 10px;">{{ frappe.utils.money_in_words(doc.total_taxes_and_charges, doc.currency) }}</span>
        </div>
        {% endif %}

        <div class="footer-section">
            <div class="sign-table">
                <div class="sign-cell sign-left">
                    Recd. in Good Condition
                </div>
                <div class="sign-cell sign-right">
                    for <span class="bold">{{ doc.company }}</span><br><br><br><br>
                    Authorised Signatory
                </div>
            </div>
        </div>
    </div>

    <div style="text-align: center; font-size: 9px; margin-top: 5px;">This is a Computer Generated Document</div>
</div>

{%- macro compact_address(address) -%}
    {%- if address -%}
        {%- set cleaned_address = address | replace('<br />', '\n') | replace('<br/>', '\n') | replace('<br>', '\n') -%}
        {%- for line in cleaned_address.split('\n') -%}
            {%- set clean_line = line | trim -%}
            {%- set lower_line = clean_line | lower -%}
            {%- if clean_line and lower_line != 'india' and lower_line[:8] != 'pin code' and lower_line[:5] != 'gstin' and lower_line[:10] != 'state name' and lower_line[:15] != 'place of supply' and 'state code' not in lower_line -%}
                <p>{{ clean_line }}</p>
            {%- endif -%}
        {%- endfor -%}
    {%- endif -%}
{%- endmacro -%}

{%- macro tally_state_line(address_name=None, gstin=None, place_of_supply=None) -%}
    {%- set ns = namespace(state_name='', state_code='') -%}
    {%- if address_name -%}
        {%- set address_doc = frappe.get_cached_doc('Address', address_name) -%}
        {%- set ns.state_name = address_doc.get('gst_state') or address_doc.get('state') or '' -%}
        {%- set ns.state_code = address_doc.get('gst_state_number') or '' -%}
    {%- endif -%}
    {%- if not ns.state_code and gstin -%}
        {%- set ns.state_code = gstin[:2] -%}
    {%- endif -%}
    {%- if not ns.state_name and place_of_supply and '-' in place_of_supply -%}
        {%- set ns.state_name = place_of_supply.split('-', 1)[1] | trim -%}
    {%- endif -%}
    {%- if not ns.state_code and place_of_supply and '-' in place_of_supply -%}
        {%- set ns.state_code = place_of_supply.split('-', 1)[0] | trim -%}
    {%- endif -%}
    {%- if ns.state_name or ns.state_code -%}
        <p>State Name : {{ ns.state_name }}{% if ns.state_code %}, Code : {{ ns.state_code }}{% endif %}</p>
    {%- endif -%}
{%- endmacro -%}

{%- macro tally_gstin_line(address_name=None, gstin=None) -%}
    {%- set ns = namespace(gstin=gstin or '') -%}
    {%- if address_name and not ns.gstin -%}
        {%- set address_doc = frappe.get_cached_doc('Address', address_name) -%}
        {%- set ns.gstin = address_doc.get('gstin') or '' -%}
    {%- endif -%}
    {%- if ns.gstin -%}
        <p>GSTIN/UIN: <span class="bold">{{ ns.gstin }}</span></p>
    {%- endif -%}
{%- endmacro -%}

{%- macro tally_place_of_supply(place_of_supply=None) -%}
    {%- if place_of_supply -%}
        {%- set pos_name = place_of_supply.split('-', 1)[1] | trim if '-' in place_of_supply else place_of_supply -%}
        <p>Place of Supply : {{ pos_name }}</p>
    {%- endif -%}
{%- endmacro -%}

<style>
    .tally-container {
        font-family: Arial, Helvetica, sans-serif;
        font-size: 10px;
        color: #000;
        width: 100%;
        margin: 0 auto;
    }
    .tally-title {
        text-align: center;
        font-weight: bold;
        font-size: 14px;
        margin-bottom: 5px;
    }
    .main-box {
        border: 1px solid #000;
        box-sizing: border-box;
    }
    p { margin: 0; padding: 0; }
    .bold { font-weight: bold; }
    .text-right { text-align: right; }
    .text-center { text-align: center; }

    /* Top Section Grid */
    .top-section {
        display: table;
        width: 100%;
        border-bottom: 1px solid #000;
        table-layout: fixed;
    }
    .left-col {
        display: table-cell;
        width: 50%;
        border-right: 1px solid #000;
        vertical-align: top;
    }
    .right-col {
        display: table-cell;
        width: 50%;
        vertical-align: top;
    }
    .address-box {
        padding: 4px;
        border-bottom: 1px solid #000;
        min-height: 85px;
        line-height: 1.35;
        box-sizing: border-box;
    }
    .address-box:last-child {
        border-bottom: none;
    }

    /* Right Column Meta Table */
    .meta-table {
        width: 100%;
        border-collapse: collapse;
        table-layout: fixed;
        empty-cells: show;
    }
    .meta-table td {
        border-bottom: 1px solid #000;
        border-right: 1px solid #000;
        padding: 2px 4px;
        vertical-align: top;
        width: 50%;
        min-height: 25px;
        box-sizing: border-box;
    }
    .meta-table td:last-child {
        border-right: none;
    }
    .meta-table tr:last-child td {
        border-bottom: none;
    }
    .meta-label {
        font-size: 9px;
    }
    .meta-val {
        font-weight: bold;
        font-size: 10px;
    }

    /* Main Items Table */
    .items-table {
        width: 100%;
        border-collapse: collapse;
        table-layout: fixed;
        empty-cells: show;
    }
    .items-table th, .items-table td {
        border-right: 1px solid #000;
        padding: 4px;
        vertical-align: top;
        box-sizing: border-box;
    }
    .items-table th:last-child, .items-table td:last-child {
        border-right: none;
    }
    .items-table th {
        border-bottom: 1px solid #000;
        text-align: left;
        font-weight: normal;
        font-size: 10px;
    }
    .items-table td {
        border-bottom: none;
    }
    .items-table .items-total-row td {
        border-top: 1px solid #000;
        border-bottom: 1px solid #000;
    }
    .items-table .bottom-line {
        border-bottom: 1px solid #000;
    }

    /* HSN Table */
    .hsn-table {
        width: 100%;
        border-collapse: collapse;
        border-bottom: 1px solid #000;
        table-layout: fixed;
        empty-cells: show;
    }
    .hsn-table th, .hsn-table td {
        border-right: 1px solid #000;
        border-bottom: 1px solid #000;
        padding: 2px 4px;
        text-align: right;
        box-sizing: border-box;
    }
    .hsn-table th {
        text-align: center;
        font-weight: normal;
    }
    .hsn-table th:first-child, .hsn-table td:first-child {
        text-align: left;
    }
    .hsn-table th:last-child, .hsn-table td:last-child {
        border-right: none;
    }

    .footer-section {
        padding: 4px;
    }
    .sign-table {
        width: 100%;
        border-top: 1px solid #000;
        display: table;
        table-layout: fixed;
        margin-top: 10px;
    }
    .sign-cell {
        display: table-cell;
        width: 50%;
        padding: 4px;
        min-height: 70px;
        vertical-align: bottom;
        box-sizing: border-box;
    }
    .sign-left {
        border-right: 1px solid #000;
    }
    .sign-right {
        text-align: right;
    }
</style>

{%- set ns = namespace(cgst_rate=0, cgst_amt=0, sgst_rate=0, sgst_amt=0, igst_rate=0, igst_amt=0) -%}
{%- for tax in doc.taxes -%}
    {%- if 'cgst' in tax.description.lower() -%}
        {%- set ns.cgst_rate = tax.rate -%}
        {%- set ns.cgst_amt = ns.cgst_amt + tax.tax_amount -%}
    {%- elif 'sgst' in tax.description.lower() or 'utgst' in tax.description.lower() -%}
        {%- set ns.sgst_rate = tax.rate -%}
        {%- set ns.sgst_amt = ns.sgst_amt + tax.tax_amount -%}
    {%- elif 'igst' in tax.description.lower() -%}
        {%- set ns.igst_rate = tax.rate -%}
        {%- set ns.igst_amt = ns.igst_amt + tax.tax_amount -%}
    {%- endif -%}
{%- endfor -%}

{%- set orig_date = '' -%}
{%- if doc.return_against -%}
    {%- set orig_date = frappe.db.get_value('Sales Invoice', doc.return_against, 'posting_date') -%}
{%- endif -%}

<div class="tally-container">
    <div class="tally-title">Credit Note</div>

    <div class="main-box">
        <div class="top-section">
            <div class="left-col">
                <div class="address-box">
                    <p class="bold" style="font-size:12px;">{{ doc.company }}</p>
