                    {{ tally_gstin_line(doc.company_address, doc.company_gstin) }}
                    {{ tally_state_line(doc.company_address, doc.company_gstin) }}
                </div>
                <div class="address-box">
                    <p>Consignee (Ship to)</p>
                    <p class="bold">{{ doc.customer_name }}</p>
                    <div style="font-size: 9px; margin-top: 2px;">{{ compact_address(doc.shipping_address or '') }}</div>
                    {{ tally_gstin_line(doc.shipping_address_name, doc.customer_gstin) }}
                    {{ tally_state_line(doc.shipping_address_name, doc.customer_gstin, doc.place_of_supply) }}
