        </div>

        <table class="items-table">
            <thead>
                <tr>
                    <th rowspan="2" class="text-center bottom-line" width="4%">Sl<br>No.</th>
                    <th rowspan="2" class="text-center bottom-line" width="7%">No. & Kind<br>of Pkgs.</th>
                    <th rowspan="2" class="text-center bottom-line" width="27%">Description of<br>Goods/Services</th>
                    <th rowspan="2" class="text-center bottom-line" width="8%">HSN/SAC</th>
                    <th rowspan="2" class="text-center bottom-line" width="6%">GST<br>Rate</th>
                    <th colspan="2" class="text-center bottom-line" width="16%">Quantity</th>
                    <th rowspan="2" class="text-center bottom-line" width="10%">Rate</th>
                    <th rowspan="2" class="text-center bottom-line" width="5%">per</th>
                    <th rowspan="2" class="text-center bottom-line" width="12%">Amount</th>
                </tr>
                <tr>
