                        </td>
                    </tr>
                    <tr>
                        <td>
                            <span class="meta-label">Original Invoice No. & Date.</span><br>
                            <span class="meta-val">{{ doc.return_against or '' }} {% if orig_date %}&nbsp; dt. {{ frappe.utils.format_date(orig_date) }}{% endif %}</span>
