    {%- endif -%}
{%- endmacro -%}

{%- macro tally_state_line(address_name=None, gstin=None, place_of_supply=None) -%}
    {%- set ns = namespace(state_name='', state_code='') -%}
    {%- if address_name -%}
        {%- set address_doc = frappe.get_cached_doc('Address', address_name) -%}
        {%- set ns.state_name = address_doc.get('gst_state') or address_doc.get('state') or '' -%}
        {%- set ns.state_code = address_doc.get('gst_state_number') or '' -%}
    {%- endif -%}
    {%- if not ns.state_code and gstin -%}
        {%- set ns.state_code = gstin[:2] -%}
    {%- endif -%}
    {%- if not ns.state_name and place_of_supply and '-' in place_of_supply -%}
        {%- set ns.state_name = place_of_supply.split('-', 1)[1] | trim -%}
    {%- endif -%}
    {%- if not ns.state_code and place_of_supply and '-' in place_of_supply -%}
        {%- set ns.state_code = place_of_supply.split('-', 1)[0] | trim -%}
    {%- endif -%}
    {%- if ns.state_name or ns.state_code -%}
        <p>State Name : {{ ns.state_name }}{% if ns.state_code %}, Code : {{ ns.state_code }}{% endif %}</p>
    {%- endif -%}
{%- endmacro -%}

{%- macro tally_gstin_line(address_name=None, gstin=None) -%}
    {%- set ns = namespace(gstin=gstin or '') -%}
    {%- if address_name and not ns.gstin -%}
        {%- set address_doc = frappe.get_cached_doc('Address', address_name) -%}
        {%- set ns.gstin = address_doc.get('gstin') or '' -%}
    {%- endif -%}
    {%- if ns.gstin -%}
        <p>GSTIN/UIN: <span class="bold">{{ ns.gstin }}</span></p>
    {%- endif -%}
{%- endmacro -%}

<style>
    .tally-container {
        font-family: Arial, Helvetica, sans-serif;
        font-size: 10px;
        color: #000;
        width: 100%;
        margin: 0 auto;
    }
    .tally-title {
        text-align: center;
        font-weight: bold;
        font-size: 14px;
        margin-bottom: 5px;
    }
    .main-box {
        border: 1px solid #000;
        box-sizing: border-box;
    }
    p { margin: 0; padding: 0; }
    .bold { font-weight: bold; }
    .text-right { text-align: right; }
    .text-center { text-align: center; }

    .top-section {
        display: table;
        width: 100%;
        border-bottom: 1px solid #000;
        table-layout: fixed;
    }
    .left-col {
        display: table-cell;
        width: 55%;
        border-right: 1px solid #000;
        vertical-align: top;
    }
    .right-col {
        display: table-cell;
        width: 45%;
        vertical-align: top;
    }
    .address-box {
        padding: 4px;
        border-bottom: 1px solid #000;
        min-height: 85px;
        line-height: 1.35;
        box-sizing: border-box;
    }
    .address-box:last-child {
        border-bottom: none;
    }

    .meta-table {
        width: 100%;
        border-collapse: collapse;
        table-layout: fixed;
        empty-cells: show;
    }
    .meta-table td {
        border-bottom: 1px solid #000;
        border-right: 1px solid #000;
        padding: 2px 4px;
        vertical-align: top;
        width: 50%;
        min-height: 25px;
        box-sizing: border-box;
    }
    .meta-table td:last-child {
        border-right: none;
    }
    .meta-table tr:last-child td {
        border-bottom: none;
    }
    .meta-label {
        font-size: 9px;
    }
    .meta-val {
        font-weight: bold;
        font-size: 10px;
    }

    .items-table {
        width: 100%;
        border-collapse: collapse;
        table-layout: fixed;
        empty-cells: show;
    }
    .items-table th, .items-table td {
        border-right: 1px solid #000;
        padding: 4px;
        vertical-align: top;
        box-sizing: border-box;
    }
    .items-table th:last-child, .items-table td:last-child {
        border-right: none;
    }
    .items-table th {
        border-bottom: 1px solid #000;
        text-align: left;
        font-weight: normal;
        font-size: 10px;
    }
    .items-table td {
        border-bottom: none;
    }
    .items-table .items-total-row td {
        border-top: 1px solid #000;
        border-bottom: 1px solid #000;
    }
    .items-table .bottom-line {
        border-bottom: 1px solid #000;
    }

    .footer-section {
        padding: 4px;
    }
    .sign-table {
        width: 100%;
        border-top: 1px solid #000;
        display: table;
        table-layout: fixed;
        margin-top: 10px;
    }
    .sign-cell {
        display: table-cell;
        width: 50%;
        padding: 4px;
        min-height: 70px;
        vertical-align: bottom;
        box-sizing: border-box;
    }
    .sign-left {
        border-right: 1px solid #000;
    }
    .sign-right {
        text-align: right;
    }
</style>

{%- set company_gstin = doc.company_gstin or frappe.db.get_value('Company', doc.company, 'gstin') -%}

<div class="tally-container">
    <div class="tally-title">Purchase Order</div>

    <div class="main-box">
        <div class="top-section">
            <div class="left-col">
                <div class="address-box">
                    <p>Invoice To</p>
                    <p class="bold" style="font-size:12px;">{{ doc.company }}</p>
                    <div style="font-size: 9px; margin-top: 2px;">{{ compact_address(doc.billing_address_display or doc.company_address_display or '') }}</div>
                    {{ tally_gstin_line(doc.billing_address or doc.company_address, company_gstin) }}
                    {{ tally_state_line(doc.billing_address or doc.company_address, company_gstin) }}
                </div>
                <div class="address-box">
                    <p>Consignee (Ship to)</p>
                    <p class="bold">{{ doc.company }}</p>
                    <div style="font-size: 9px; margin-top: 2px;">{{ compact_address(doc.shipping_address_display or doc.billing_address_display or doc.company_address_display or '') }}</div>
                    {% if doc.shipping_address %}
                        {{ tally_gstin_line(doc.shipping_address, company_gstin) }}
                        {{ tally_state_line(doc.shipping_address, company_gstin) }}
                    {% else %}
                        {{ tally_gstin_line(doc.billing_address or doc.company_address, company_gstin) }}
                        {{ tally_state_line(doc.billing_address or doc.company_address, company_gstin) }}
                    {% endif %}
                </div>
                <div class="address-box">
                    <p>Supplier (Bill from)</p>
                    <p class="bold">{{ doc.supplier_name }}</p>
                    <div style="font-size: 9px; margin-top: 2px;">{{ compact_address(doc.address_display or '') }}</div>
                    {{ tally_gstin_line(doc.supplier_address, doc.supplier_gstin) }}
                    {{ tally_state_line(doc.supplier_address, doc.supplier_gstin, doc.place_of_supply) }}
                </div>
            </div>

            <div class="right-col">
                <table class="meta-table">
                    <tr>
                        <td>
                            <span class="meta-label">Voucher No.</span><br>
                            <span class="meta-val">{{ doc.name }}</span>
                        </td>
                        <td>
                            <span class="meta-label">Dated</span><br>
                            <span class="meta-val">{{ doc.get_formatted("transaction_date") }}</span>
                        </td>
                    </tr>
                    <tr>
                        <td>
                            <span class="meta-label">&nbsp;</span><br>
                            <span class="meta-val">&nbsp;</span>
                        </td>
                        <td>
                            <span class="meta-label">Mode/Terms of Payment</span><br>
                            <span class="meta-val">{{ doc.payment_terms_template or '' }}</span>
                        </td>
                    </tr>
                    <tr>
                        <td>
                            <span class="meta-label">Reference No. & Date.</span><br>
                            <span class="meta-val">&nbsp;</span>
                        </td>
                        <td>
                            <span class="meta-label">Other References</span><br>
                            <span class="meta-val">&nbsp;</span>
                        </td>
                    </tr>
                    <tr>
                        <td>
                            <span class="meta-label">Dispatched through</span><br>
                            <span class="meta-val">&nbsp;</span>
                        </td>
                        <td>
                            <span class="meta-label">Destination</span><br>
                            <span class="meta-val">&nbsp;</span>
                        </td>
                    </tr>
                    <tr>
                        <td colspan="2" style="border-right: none; min-height: 60px; box-sizing: border-box;">
                            <span class="meta-label">Terms of Delivery</span><br>
                            <span class="meta-val">&nbsp;</span>
                        </td>
                    </tr>
                </table>
            </div>
        </div>

        <table class="items-table">
            <thead>
                <tr>
                    <th class="text-center bottom-line" width="4%">Sl<br>No.</th>
                    <th class="text-center bottom-line" width="7%">No. & Kind<br>of Pkgs.</th>
                    <th class="text-center bottom-line" width="30%">Description of Goods</th>
                    <th class="text-center bottom-line" width="10%">Due on</th>
                    <th class="text-center bottom-line" width="14%">Quantity</th>
                    <th class="text-center bottom-line" width="12%">Rate</th>
                    <th class="text-center bottom-line" width="5%">per</th>
                    <th class="text-center bottom-line" width="15%">Amount</th>
                </tr>
            </thead>
            <tbody>
                {% for row in doc.items %}
                <tr>
                    <td class="text-center">{{ loop.index }}</td>
                    <td class="text-center">&nbsp;</td>
                    <td>
                        <span class="bold">{{ row.item_name }}</span>
                        {% if row.description and row.description != row.item_name %}
                        <br><i style="font-size: 9px;">{{ row.description | truncate(80) | striptags }}</i>
                        {% endif %}
                    </td>
                    <td class="text-center">{{ frappe.utils.format_date(row.schedule_date) if row.schedule_date else '' }}</td>
                    <td class="text-right">{{ row.qty }} {{ row.uom }}</td>
                    <td class="text-right">{{ row.get_formatted("rate") }}</td>
                    <td>{{ row.uom }}</td>
                    <td class="text-right bold">{{ row.get_formatted("amount") }}</td>
                </tr>
                {% endfor %}

                {% for tax in doc.taxes %}
                <tr>
                    <td></td><td></td>
                    <td class="text-right">
                        {% if 'round' in tax.description.lower() %}
                            <i>Less : &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span class="bold">{{ tax.description }}</span></i>
                        {% else %}
                            <i class="bold">{{ tax.description }}</i>
                        {% endif %}
                    </td>
                    <td></td><td></td><td></td><td></td>
                    <td class="text-right bold">{% if 'round' in tax.description.lower() and tax.tax_amount < 0 %}(-){{ frappe.utils.fmt_money(tax.tax_amount | abs, currency=doc.currency) }}{% else %}{{ tax.get_formatted("tax_amount") }}{% endif %}</td>
                </tr>
                {% endfor %}


                {% if doc.rounding_adjustment %}
                <tr>
                    <td></td><td></td>
                    <td class="text-right">
                        <i>{% if doc.rounding_adjustment < 0 %}Less : &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {% endif %}<span class="bold">Round Off</span></i>
                    </td>
                    <td></td><td></td><td></td><td></td>
                    <td class="text-right bold">{% if doc.rounding_adjustment < 0 %}(-){{ frappe.utils.fmt_money(doc.rounding_adjustment | abs, currency=doc.currency) }}{% else %}{{ frappe.utils.fmt_money(doc.rounding_adjustment, currency=doc.currency) }}{% endif %}</td>
                </tr>
                {% endif %}

                <tr style="height: 120px;">
                    <td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td>
                </tr>

                <tr class="items-total-row">
                    <td></td><td></td>
                    <td class="text-right bold">Total</td>
                    <td></td>
                    <td class="text-right bold">{{ doc.total_qty }} {{ doc.items[0].uom if doc.items else '' }}</td>
                    <td></td><td></td>
                    <td class="text-right bold">{{ frappe.utils.fmt_money((doc.rounded_total or doc.grand_total), currency=doc.currency) }}</td>
                </tr>
            </tbody>
        </table>

        <div style="padding: 4px; border-bottom: 1px solid #000;">
            <div style="float: right; font-style: italic;">E. & O.E</div>
            <span style="font-size: 9px;">Amount Chargeable (in words)</span><br>
            <span class="bold">{{ frappe.utils.money_in_words(doc.rounded_total or doc.grand_total, doc.currency) }}</span>
        </div>

        <div class="footer-section">
            <div class="sign-table">
                <div class="sign-cell sign-left">
                    &nbsp;
                </div>
                <div class="sign-cell sign-right">
                    for <span class="bold">{{ doc.company }}</span><br><br><br><br>
                    <i>Authorised Signatory</i>
                </div>
            </div>
        </div>
    </div>

    <div style="text-align: center; font-size: 9px; margin-top: 5px;">This is a Computer Generated Document</div>
</div>
